<script>
 const player = ImageKitVideoPlayer.videoPlayer(&#x27;my-player&#x27;, {
 imagekitId: &#x27;YOUR_IMAGEKIT_ID&#x27;,
 seekThumbnails: true, // Show previews on hover
 floatingWhenNotVisible: &#x27;right&#x27; // Sticky player on scroll
 });

player.src({
 src: &#x27;https://ik.imagekit.io/<your-imagekit-id>/video.mp4&#x27;,

 // AI-powered features - no manual work required!
 chapters: true, // Auto-generate chapters from video content
 textTracks: [{
 autoGenerate: true, // AI speech-to-text transcription
 default: true,
