 Complete API Reference

use ImageKit\ImageKit; 

// For demonstration purposes, the documentation would use https://ik.imagekit.io/demo as urlEndpoint
$imageKit = new ImageKit(
 "publicKey",
 "privateKey",
 "urlEndpoint"
);
