 data: [{
 createdAt: "2020-12-15T08:33:04.570Z",
 customCoordinates: null,
 fileId: "5fd874c040308546019f0500",
 filePath: "/rally_s_tK613HYyf.jpg",
 fileType: "image",
 isPrivateFile: false,
