 imagekitId: &#x27;YOUR_IMAGEKIT_ID&#x27;
});

// Listen to common events
player.on(&#x27;play&#x27;, () => console.log(&#x27;Playing&#x27;));
player.on(&#x27;pause&#x27;, () => console.log(&#x27;Paused&#x27;));
player.on(&#x27;ended&#x27;, () => console.log(&#x27;Ended&#x27;));
player.on(&#x27;timeupdate&#x27;, () => {
